// Detectar si el usuario pidió los pasos de una receta específica
const output = $('agente-recetas').item.json.output || '';
const mensajeUsuario = $('preparar-contexto').item.json.mensaje_actual || '';

// Buscar nombre de receta entre comillas (ej: Quiero hacer "Arroz con pollo")
// O extraerlo de frases como 'hacer X detallado', 'preparar X'
const matchComillas = mensajeUsuario.match(/["«“](.*?)["»”]/);
const matchHacer = mensajeUsuario.match(/(?:hacer|preparar|cocinar)\s+(?:la\s+|el\s+|los\s+|las\s+)?([\w\s]+?)(?:,|\.|$)/i);
const nombreReceta = matchComillas ? matchComillas[1].trim()
                   : matchHacer   ? matchHacer[1].trim()
                   : null;

// Buscar video si el usuario pide pasos/receta
const pidePasos = /pasos|preparar|hacer|cocinar|dame|cómo/i.test(mensajeUsuario) && nombreReceta;

return [{
  json: {
    output,
    nombre_receta: nombreReceta || '',
    buscar_video: !!pidePasos,
    imagen_url: null
  }
}];

// Obtener el nodo anterior
const prev = $('detectar-receta').first().json;
const nombreReceta = prev.nombre_receta || '';

// Crear el término de búsqueda limpio
const queryBusqueda = `como preparar ${nombreReceta} receta paso a paso`;

return [{
  json: {
    // Mantenemos los datos anteriores para no perderlos en el flujo
    output: prev.output,
    imagen_url: prev.imagen_url || null,
    // Pasamos el término que usará el buscador de YouTube
    termino_busqueda: queryBusqueda,
    nombre_receta: nombreReceta
  }
}];

// Extraer datos del primer resultado de la búsqueda de YouTube
const yt = $input.first().json || {};
const videoId = (yt.id && yt.id.videoId) ? yt.id.videoId : null;
const snippet = yt.snippet || {};
const thumbs = snippet.thumbnails || {};
const thumbnail = (thumbs.high && thumbs.high.url)
  || (thumbs.medium && thumbs.medium.url)
  || (thumbs.default && thumbs.default.url)
  || null;

// Recuperar output e imagen_url del contexto previo
const prev = $('buscar-video-youtube').first().json;

return [{ json: {
  output: prev.output,
  imagen_url: prev.imagen_url || null,
  video_url: videoId ? `https://www.youtube.com/watch?v=${videoId}` : null,
  video_titulo: snippet.title || null,
  video_thumbnail: thumbnail
}}];

